```rust
fn register_component(&mut self, name: &str, component: T, behavior: DuplicateBehavior) -> Result<(), McpError> {
    if self.components.contains_key(name) {
        match behavior {
            DuplicateBehavior::Error => return Err(McpError::duplicate(name)),
            DuplicateBehavior::Warn => {
                log::warn!("Duplicate component '{}', keeping original", name);
                return Ok(());
            }
            DuplicateBehavior::Replace => {
                log::debug!("Replacing component '{}'", name);
            }
            DuplicateBehavior::Ignore => return Ok(()),
        }
    }
    self.components.insert(name.to_owned(), component);
    Ok(())
}
